</template>

<script>
import Header from '@/components/common/header/index.vue';
import Lottery from '@/components/common/lottery/Lottery'
import cusPreviewImg from '@/components/cus-previewImg/cus-previewImg.vue'
import Login from "@/components/common/login/Login";
import Ads from '@/components/common/ad/Ad'
import Comment from "@/components/common/comment/Comment";
import ReplyComment from "@/components/common/comment/ReplyComment";
import Fab from "@/components/common/fab/Fab";
import Vote from "@/components/common/vote/Vote";
import Share from "@/components/common/share/Share";
import {
	mapGetters
} from 'pinia';
import {
	detail,
	recommendPicture,
	latest
} from '@/utils/picture/index.js'
import {
	period
} from '@/utils/lottery/index.js'
import {
	advertList,
	listSpreadByType
} from "@/utils/common/index.js"
import {
	collect,
	thumbUp
} from "@/utils/user/index.js"
import AlertInjectLayer from "@/components/common/alert/AlertInjectLayer.vue"

export default {
	name: "detail",
	components: {
		Header,
		Vote,
		Lottery,
		cusPreviewImg,
		Login,
		Ads,
		Comment,
		ReplyComment,
		Fab,
		Share,
		AlertInjectLayer,
	},
	computed: {
		...mapGetters(["themeColor", "uWindowHeight", "windowBottom", "downloadShow"]),
		pageUiLoading() {
			return this.$config.configUIMgr.page_loading_row['t1'];
		},
		yearRangeList() {
			return this.yearList.map(item => {
				return {
					value: item.year,
					text: item.name
				}
			})
		}
	},

	data() {
		return {
			downloadIconShow: false,
			scrollIntoView: '',
			safeHeight: this.$config.getStorageSync(this.$config.enumMgr.APP_LOCALSTORE_KEYS.SYSTEM_INFO).safeArea
				.top + "px",
			title: this.$t('pages.luntan.liuhePicture.detail.viewDetails'),
			curr: 0,
			selectText: this.$t('pages.luntan.liuhePicture.detail.selectOption'),
			scrollTop: 0,
			isTop: 0, //吸附判断
			isShow: false,
			voteShow: false,
			old: {
				scrollTop: 0,
				myScroll: 0,
			},
			yearList: [],
			periodList: [],
			pictureId: 0,
			info: {},
			lottery: {},
			listPicture: [],
			ImgList: [],
			animalId: 0,
			recommendPictureList: [],
			pageNum: 0,
			loadMoreText: this.$t('pages.luntan.liuhePicture.detail.loadMore'),
			isLoadMorePic: false,
			showLogin: false,
			loadIndex: 0,
			is_transition: false,
			translateX: 0,
			initDetailRequsetSuccess: false,
			initDecommendPictureSuccess: false,
			isApp: false
		}
	},
	mounted() {
		uni.$emit("on_page_mounted", this)
		this.isApp = browserPlatform() == browserPlatform.FLUTTER_App;
	},
	onLoad(option) {
		//方式一：接收参数
		this.pictureId = parseInt(option.id)
		this.detail()
		this.listSpreadByType()
		this.navY()
		uni.setNavigationBarTitle({
			title: this.title
		});
	},
	methods: {
		getText(type) {
			const textMap = {
				left: this.translateX < 40 ? this.$t('pages.luntan.liuhePicture.detail.continueSwipeRight') : this
					.$t('pages.luntan.liuhePicture.detail.releaseToLoadPrev'),
				right: this.translateX < -40 ? this.$t('pages.luntan.liuhePicture.detail.releaseToLoadNext') : this
					.$t('pages.luntan.liuhePicture.detail.continueSwipeLeft'),
			}
			return textMap[type]
		},
		touchstart({
			touches
		}) {
			this.is_transition = false
			const {
				pageX
			} = touches[0]
			this.startPageX = pageX
		},
		touchmove({
			touches
		}) {
			const {
				pageX
			} = touches[0]
			if (this.translateX > 0 && this.loadIndex <= 0) {
				return
			}
			if (this.translateX < 0 && this.loadIndex >= this.periodList.length - 1) {
				return
			}
			this.translateX = pageX - this.startPageX
		},
		touchend() {
			this.loadIndex = this.periodList.findIndex(item => item.pictureId === this.pictureId)
			let isLoad = false
			if (this.translateX < 0 && this.translateX < -40 && this.periodList.length > this.loadIndex + 1) {
				this.loadIndex++
				isLoad = true
			} else if (this.translateX > 0 && this.translateX > 40 && this.loadIndex > 0) {
				this.loadIndex--
				isLoad = true
			}

			if (isLoad) {
				this.selectPeriod(this.periodList[this.loadIndex], this.loadIndex)
			}
			this.is_transition = true
			this.translateX = 0
		},
		back: function () {
			uni.navigateBack()
		},
		tiaozhuan: function (id) {
			uni.navigateTo({
				url: "detail?id=" + id // 返回的页面数，如果 delta 大于现有页面数，则返回到首页
			});
		},
		tujie: function () {
			uni.navigateTo({
				url: "tujie?id=" + this.pictureId // 返回的页面数，如果 delta 大于现有页面数，则返回到首页
			});
		},
		lishi: function () {
			uni.navigateTo({
				url: '/pages/luntan/historyLottery/lottery?lotteryType=' + uni.getStorageSync(
					'lotteryType')
				// page.json定义的路径 传url 到webview界面去接收 实现跳转
			})
		},
		navY: function () {
			this.$nextTick(function () {
				/*下次 DOM 更新时，找到某个控件，再进行复杂计算并确定其高度后*/
				const query = uni.createSelectorQuery();
				query.select('.comment-list').boundingClientRect(data => {
					this.old.myScroll = data.height;
				}).exec();
			});
		},
		//展开
		zhankai: function () {
			this.voteShow = !this.voteShow
			this.navY()
		},
		//分享弹窗
		fenxiang: function () {
			this.$refs.share.open()
		},
		//关闭分享
		closefx: function () {
			this.$refs.share.close()
		},
		//加载更多
		lower: function (e) {
			if (!this.isLoadMore) { //此处判断，上锁，防止重复请求
				this.isLoadMore = true
				this.$refs.comment.listLatest()
			}
		},
		setIsLoadMore: function () {
			this.isLoadMore = false
		},
		previewImg: function (imgList, url) { // 点击预览图片
			this.ImgList = []
			this.ImgList.push(imgList)
			this.$refs.cusPreviewImg.open(url) // 传入当前选中的图片地址
		},
		downImg(url) {
			// #ifdef APP-PLUS

			// #endif
			// #ifdef H5
			this.$nativeBridge.saveImageByUrl(url, function (res) {
				if (res.code == -1) {
					var oA = document.createElement("a");
					oA.download = 'a'; // 设置下载的文件名，默认是'下载'
					oA.href = url;
					document.body.appendChild(oA);
					oA.click();
					oA.remove();
				} else {
					pop(res.msg);
				}
			}, this);
			// #endif
		},
		//滚动条监听
		scroll: function (e) {
			this.old.scrollTop = e.detail.scrollTop
			if ((this.old.scrollTop) >= this.old.myScroll) {
				this.isTop = 1
			} else {
				this.isTop = 0
			}
		},
		//选择年
		selectYears(year) {
			this.curr = this.yearList.findIndex(item => item.year === year)
			let prams = {
				pictureTypeId: this.info.pictureTypeId,
				year
			}
			uni.showLoading({
				title: this.$t('pages.luntan.liuhePicture.detail.loading')
			});
			latest(prams).then(res => {
				uni.hideLoading()
				this.yearList = res.result.yearList
				this.periodList = res.result.periodList
				if (this.periodList.length) {
					this.pictureId = this.periodList[0].pictureId
					this.scrollIntoView = 'scroll-view-0'
				}
				this.info = res.result
				this.period()
				this.recommendPicture()
			}).catch(err => {
				console.log(err)
			})
		},
		//选择期
		async selectPeriod(item, index) {
			// this.scrollIntoView = 'scroll-view-' + index
			uni.showLoading({
				title: this.$t('pages.luntan.liuhePicture.detail.loading')
			});
			this.pictureId = item.pictureId
			await this.detail()
			uni.hideLoading();
			this.selectText = this.$t('pages.luntan.liuhePicture.detail.issue') + this.info.period + this.$t(
				'pages.luntan.liuhePicture.detail.period')
			this.isShow = false
			this.$refs.comment.restComment()
		},
		//详情
		async detail() {
			let that = this;
			let prams = {
				pictureId: this.pictureId
			}
			await detail(prams).then(res => {
				this.$requestCache.bindLastCacheUpdateApiCallBack(res, this.bindDetailsResponseData, this);
				this.bindDetailsResponseData(res);
				this.$nextTick(function () {
					that.initDetailRequsetSuccess = true;
				})
				this.period()
				this.recommendPicture();

			}).catch(err => {
				console.log(err)
			})
		},
		bindDetailsResponseData(res) {
			this.yearList = res.result.yearList
			if (res.result?.yearList.length && !this.curr) {
				this.curr = res.result.yearList[0].year
			}
			this.periodList = res.result.periodList
			this.info = res.result
		},


		//根据期数获取彩票信息
		period: function () {
			let prams = {
				lotteryType: this.$config.getStorageSync(this.$config.enumMgr.APP_LOCALSTORE_KEYS
					.LOCAL_STORE_LOTTERYTYPE),
				number: this.info.period,
				year: this.info.year,
			}
			period(prams).then(res => {
				this.$requestCache.bindLastCacheUpdateApiCallBack(res, (netRes) => {
					this.lottery = netRes.result
				}, this)
				this.lottery = res.result
			}).catch(err => {
				console.log(err)
			})
		},
		//打开登录界面
		openPopup: function () {
			if (this.$config.station === 'LUNTAN') {
				this.showLogin = true
				return
			}
			uni.$emit('showPop', {
				refName: 'AlertMessage'
			})
		},
		//打开评论
		replyComment: function () {
			if (!isLogin()) {
				if (this.$config.station === 'LUNTAN') {
					this.showLogin = true
					return
				}
				uni.$emit('showPop', {
					refName: 'AlertMessage'
				})
				return false
			}
			this.$refs.comentPopup.open('right')
		},
		//关闭评论
		closeComent: function () {
			this.$refs.comentPopup.close()
			this.$refs.comment.restComment()
			this.detail()
		},
		//轮播图获取
		listSpreadByType: function () {
			let prams = {
				projectType: 1,
				code: 3,
			}
			advertList(prams).then(res => {
				this.listPicture = res.result
			}).catch(err => {

			})
		},
		//收藏
		collect: function () {
			if (!isLogin()) {
				if (this.$config.station === 'LUNTAN') {
					this.showLogin = true
					return
				}
				uni.$emit('showPop', {
					refName: 'AlertMessage'
				})
				return false
			}
			let prams = {
				relatedId: this.info.pictureTypeId,
				type: 1
			}
			collect(prams).then(res => {
				if (res.code == 200) {
					this.info.collect = res.result
					if (res.result == 1) {
						this.info.collectCount++
					} else {
						this.info.collectCount--
					}
				}
				pop(res.message, 2000)
			}).catch(err => {
				console.log(err)
			})
		},
		//点赞接口
		thumbUp: function () {
			if (!isLogin()) {
				if (this.$config.station === 'LUNTAN') {
					this.showLogin = true
					return
				}
				uni.$emit('showPop', {
					refName: 'AlertMessage'
				})
				return false
			}
			let prams = {
				relatedId: this.pictureId,
				type: 1,
				createTime: this.info.createTime
			}
			thumbUp(prams).then(res => {
				pop(res.message, 2000)
				if (res.code == 200) {
					this.info.thumbUp = 1
					this.info.thumbUpCount++
				}
			}).catch(err => {
				console.log(err)
			})
		},
		//投票
		openVote: function () {
			if (!isLogin()) {
				if (this.$config.station === 'LUNTAN') {
					this.showLogin = true
					return
				}
				uni.$emit('showPop', {
					refName: 'AlertMessage'
				})
				return false
			}
			this.$nativeBridge.setStatusBarColor('#b2b2b2')

			this.$refs.vote.open()
		},
		//关闭投票
		closeVote: function () {
			this.$nativeBridge.setStatusBarColor('#ffffff')

			this.$refs.vote.close()
			this.detail()
		},
		//投票记录
		voteDetail: function () {
			uni.navigateTo({
				url: "voteDetails?pictureId=" + this.pictureId + '&curr=' + this
					.curr // 返回的页面数，如果 delta 大于现有页面数，则返回到首页
			});
		},
		//推荐
		recommendPicture: function () {
			if (this.isLoadMorePic) {
				return false
			}
			let that = this;
			this.pageNum++
			let prams = {
				pageNum: this.pageNum,
				pictureId: this.pictureId,
				year: this.info.year
			}
			recommendPicture(prams).then(res => {
				this.$nextTick(() => {
					that.initDecommendPictureSuccess = true;
				});
				this.recommendPictureList.push(...res.result.records)
				if (res.result.pages <= this.pageNum) {
					this.loadMoreText = this.$t('pages.luntan.liuhePicture.detail.loadedAll')
					this.isLoadMorePic = true
				}
			}).catch(err => {
				console.log(err)
			})
		}
	}
}
</script>

